// Keyword → category mapping for trend matching
export const KEYWORD_CATEGORY_MAP: Record<string, string[]> = {
  "gadgets-voiture": ["voiture", "auto", "car", "driving", "conducteur", "drive", "road", "parking", "gps", "dashcam"],
  "maison-intelligente": ["maison", "home", "smart", "connecté", "connected", "alexa", "google home", "domotique", "aspirateur", "vacuum", "robot", "wifi"],
  "cuisine-pratique": ["cuisine", "kitchen", "cook", "food", "recette", "recipe", "friteuse", "fryer", "robot", "café", "coffee", "baking", "pâtisserie"],
  "sport-fitness": ["sport", "fitness", "gym", "muscle", "workout", "running", "yoga", "pilates", "massage", "récupération", "recovery", "healthy", "santé"],
  "beaute-soin": ["beauté", "beauty", "skin", "soin", "skincare", "visage", "face", "cheveux", "hair", "lifting", "anti-âge", "anti-aging", "makeup"],
  "tech-gadgets": ["tech", "gadget", "phone", "bluetooth", "écouteurs", "earbuds", "enceinte", "speaker", "chargeur", "charger", "laptop", "mac"],
  "bureau-productivite": ["bureau", "desk", "office", "work", "télétravail", "remote", "productivité", "productivity", "organisation", "planning"],
  "enfant-famille": ["enfant", "kids", "children", "famille", "family", "bébé", "baby", "jouet", "toy", "naissance", "birth"],
};

export function matchTrendToCategories(trends: string[]): string[] {
  const scores: Record<string, number> = {};
  for (const trend of trends) {
    const lowerTrend = trend.toLowerCase();
    for (const [category, keywords] of Object.entries(KEYWORD_CATEGORY_MAP)) {
      for (const kw of keywords) {
        if (lowerTrend.includes(kw)) {
          scores[category] = (scores[category] || 0) + 1;
        }
      }
    }
  }
  // Sort by score, fallback to all categories
  const sorted = Object.entries(scores).sort(([, a], [, b]) => b - a).map(([cat]) => cat);
  // Always include all categories (in shuffled order) as fallback
  const allCats = Object.keys(KEYWORD_CATEGORY_MAP);
  const remaining = allCats.filter(c => !sorted.includes(c));
  return [...sorted, ...remaining];
}
